const input = items?.[0]?.json ?? {};

function getNodeItemJson(nodeName) {
  try {
    return $items(nodeName, 0, 0)?.[0]?.json ?? {};
  } catch (error) {
    return {};
  }
}

const createProduct = getNodeItemJson("Create Product");
const fullDataNoImages = getNodeItemJson("Product FULL DATA - no images");
const source = fullDataNoImages?.custom ?? fullDataNoImages;

function normalizeProductGid(raw) {
  if (raw == null || raw === "") return null;
  const value = String(raw).trim();
  if (value.startsWith("gid://shopify/Product/")) return value;
  const id = value.includes("/") ? value.split("/").pop() : value;
  return id ? `gid://shopify/Product/${id}` : null;
}

function normalizeMediaImageGid(raw) {
  if (raw == null || raw === "") return "";
  const value = String(raw).trim();
  if (value.startsWith("gid://shopify/MediaImage/")) return value;
  const id = value.includes("/") ? value.split("/").pop() : value;
  return id ? `gid://shopify/MediaImage/${id}` : "";
}

const productId = normalizeProductGid(
  createProduct?.data?.productCreate?.product?.id ??
  source?.product_id ??
  input?.product_id ??
  input?.data?.productCreate?.product?.id ??
  null
);

if (!productId) {
  throw new Error("Missing product id from Create Product1");
}

const NAMESPACE = "custom";

const firstBatchSchema = [
  { key: "beneficiu_1", type: "rich_text_field" },
  { key: "beneficiu_2", type: "rich_text_field" },
  { key: "beneficiu_3", type: "rich_text_field" },
  { key: "beneficiu_4", type: "rich_text_field" },
  { key: "section_1_title", type: "single_line_text_field" },
  { key: "section_1_description", type: "rich_text_field" },
  { key: "section_2_title", type: "single_line_text_field" },
  { key: "section_2_description", type: "rich_text_field" },
  { key: "section_3_title", type: "single_line_text_field" },
  { key: "section_3_description", type: "rich_text_field" },
  { key: "rev_1_text", type: "rich_text_field" },
  { key: "rev_1_name", type: "single_line_text_field" },
  { key: "rev_2_text", type: "rich_text_field" },
  { key: "rev_2_name", type: "single_line_text_field" },
  { key: "rev_3_text", type: "rich_text_field" },
  { key: "rev_3_name", type: "single_line_text_field" },
  { key: "rev_4_text", type: "rich_text_field" },
  { key: "rev_4_name", type: "single_line_text_field" },
  { key: "rev_5_text", type: "rich_text_field" },
  { key: "rev_5_name", type: "single_line_text_field" },
];

const secondBatchSchema = [
  { key: "faq_1_q", type: "single_line_text_field" },
  { key: "faq_1_a", type: "rich_text_field" },
  { key: "faq_2_q", type: "single_line_text_field" },
  { key: "faq_2_a", type: "rich_text_field" },
  { key: "faq_3_q", type: "single_line_text_field" },
  { key: "faq_3_a", type: "rich_text_field" },
  { key: "faq_4_q", type: "single_line_text_field" },
  { key: "faq_4_a", type: "rich_text_field" },
  { key: "rev_5_img", type: "file_reference" },
  { key: "rev_4_img", type: "file_reference" },
  { key: "rev_3_img", type: "file_reference" },
  { key: "rev_2_img", type: "file_reference" },
  { key: "rev_1_img", type: "file_reference" },
  { key: "section_3_image", type: "file_reference" },
  { key: "section_2_image", type: "file_reference" },
  { key: "section_1_image", type: "file_reference" },
];

function toRichTextFieldString(value) {
  return JSON.stringify({
    type: "root",
    children: [
      {
        type: "paragraph",
        children: [
          {
            type: "text",
            value: value == null ? "" : String(value),
          },
        ],
      },
    ],
  });
}

const fallbackImageId = normalizeMediaImageGid(
  source?.image_id ??
  fullDataNoImages?.image_id ??
  input?.image_id ??
  null
);

function formatValue(type, rawValue) {
  if (type === "rich_text_field") {
    return toRichTextFieldString(rawValue);
  }

  if (type === "single_line_text_field") {
    return rawValue == null ? "" : String(rawValue);
  }

  if (type === "file_reference") {
    const candidate = rawValue == null || rawValue === "" ? fallbackImageId : rawValue;
    return normalizeMediaImageGid(candidate);
  }

  return rawValue == null ? "" : String(rawValue);
}

function buildMetafields(schema) {
  return schema.map(({ key, type }) => ({
    ownerId: productId,
    namespace: NAMESPACE,
    key,
    type,
    value: formatValue(type, source[key]),
  }));
}

const firstBatch = {
  metafields: buildMetafields(firstBatchSchema),
};

const secondBatch = {
  metafields: buildMetafields(secondBatchSchema),
};

const firstBatchString = JSON.stringify(firstBatch);
const secondBatchString = JSON.stringify(secondBatch);

return [
  { json: { variables: firstBatchString } },
  { json: { variables: secondBatchString } },
];

