const productPatterns = [
  /amazon\.[a-z.]+\/.*\/dp\//i,
  /aliexpress\.com\/(item|i)\//i,
  /ebay\.[a-z.]+\/itm\//i,
  /walmart\.[a-z.]+\/ip\//i,
  /wayfair\.com\/.*\/pdp\//i,
];

// Optional: block obvious non-product pages
const excludePatterns = [
  /showroom/i,
  /category/i,
  /search/i,
];

return items.filter(item => {
  const url = item.json.link;

  if (!url) return false;

  const isProduct = productPatterns.some(regex => regex.test(url));
  const isExcluded = excludePatterns.some(regex => regex.test(url));

  return isProduct && !isExcluded;
});

return $input.all().flatMap((item) =>
  (item.json.organic || []).map((result) => ({
    json: {
      title: result.title || '',
      source: result.source || '',
      link: result.link || '',
      imageUrl: result.imageUrl || result.thumbnailUrl || '',
    },
  }))
);

return [
  {
    json: {
      imageUrl: "",
      title: "",
      source: "",
      link: ""
    }
  }
];

