mutation CreateProductWithMedia($product: ProductCreateInput!, $media: [CreateMediaInput!]) {
  productCreate(product: $product, media: $media) {
    product {
      id
      title
      descriptionHtml
      status
      templateSuffix
      variants(first: 1) {
        nodes {
          id
          price
          compareAtPrice
        }
      }
      media(first: 30) {
        nodes {
          id
          alt
          mediaContentType
        }
      }
    }
    userErrors {
      field
      message
    }
  }
}

